insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'aichi' and m.slug = 'nagoya'), 'aichi-nagoya-prenatal-postpartum-helper', '産前・産後ヘルプ事業', '名古屋市が実施する産前・産後ヘルプ事業です。妊娠中または出産後間もない時期に体調がすぐれないため家事や育児が困難であり、かつ昼間に家事や育児を手伝ってくれる同居の家族等が他にいない方を対象に、ヘルパーを家庭に派遣して、調理・洗濯・掃除などの家事や、授乳の手伝い・沐浴の介助などの育児を援助します。利用は1日4時間まで、期間中の合計80時間（多胎妊娠・出産の場合は100時間）までとなる可能性があると公式に記載されています。利用できる期間は、令和7年10月1日以降の利用分から「妊娠中（母子健康手帳交付後）から出産後1年以内」または「母もしくは子の入院終了後2か月以内」のいずれか長い期間に拡充されています。利用料は世帯の生計中心者の市民税課税状況により1時間あたり0円・125円・805円のいずれかとなる可能性があります。里帰り出産中の方や、昼間に家事・育児を手伝える家族が他にいる場合は対象外となる可能性があります。名古屋市が別に実施する産後ケア事業（助産師等による母子の心身のケア）や、ファミリー・サポート・センター事業（会員同士の相互援助）とは異なる、市によるヘルパー派遣事業です。', '妊娠中や出産のあとで、体調が悪くて家事や育児がつらいのに、昼間に手伝ってくれる家族が身近にいないとき、名古屋市のヘルパーが家に来て、料理・洗濯・掃除や赤ちゃんのお世話を手伝ってくれる制度です。利用したいときは早めにお住まいの区役所に申し込みます。', 'service', '名古屋市内に住所を有し、妊娠中または出産後間もない時期に体調不良等により家事や育児が困難であり、かつ昼間に家事や育児を手伝ってくれる同居者等が他にいない方が対象となる可能性があります。里帰り出産中の方や、昼間に援助可能な家族が他にいる場合は対象外となる可能性があるとされています。', '1日4時間まで、期間中合計80時間（多胎妊娠・出産の場合は100時間）まで利用できる可能性があります。利用料は世帯の生計中心者の市民税課税状況により、A区分（生活保護世帯・市民税非課税世帯）は1時間0円、B区分（市民税均等割のみ課税）は1時間125円、C区分（その他）は1時間805円となる可能性があります。利用できる期間は、令和7年10月1日以降の利用分から、妊娠中（母子健康手帳交付後）から出産後1年以内、または母もしくは子の入院終了後2か月以内のいずれか長い期間とされています。', '申込期間は原則、派遣を希望する期間の開始日の3か月前から2週間前までとされています。急な申込みには対応できない場合があるとされています。', 'お住まいの区の区民生子ども課、または支所区民福祉課の窓口に、産前・産後ヘルプ事業利用申込書を提出する方法とされています。オンライン申請の記載は確認できませんでした。', '産前・産後ヘルプ事業利用申込書、母子健康手帳が必要とされています。', FALSE, '名古屋市 子ども青少年局 子育て支援部 子育て支援課 子育て支援担当', '052-972-3083', NULL, 'https://www.city.nagoya.jp/kodomoseishonen/page/0000096194.html', '産前・産後ヘルプ事業（子育て）｜名古屋市公式ウェブサイト', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'onlineApplicationAvailable']::text[], '対象条件・利用できる時間や回数の上限・利用料は世帯状況や名古屋市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず名古屋市の公式サイトおよびお住まいの区役所民生子ども課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
