insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"aichi-nagoya-prenatal-postpartum-helper","status":"published","title":"産前・産後ヘルプ事業","officialUrl":"https://www.city.nagoya.jp/kodomoseishonen/page/0000096194.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:aichi-nagoya-prenatal-postpartum-helper:YWljaGktbmFnb3lhLXByZW5hdGFsLXBvc3RwYXJ0dW0taGVscGVyfFZGajFBVWgxS2ordlRsWERJY2Y2WmE0WA==' from public.support_programs sp where sp.slug='aichi-nagoya-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'chiba' and m.slug = 'chiba'), 'chiba-chiba-prenatal-postpartum-helper', 'エンゼルヘルパー派遣事業', '千葉市が実施するエンゼルヘルパー派遣事業です。妊娠中または出産後で、昼間に家事・育児を手伝ってくれる家族などが身近にいない世帯に、市と契約したヘルパー事業者から支援員を派遣し、食事の準備・洗濯・掃除といった家事援助、授乳の手伝い・おむつ交換・沐浴の介助といった育児援助、通院や保育園送迎などの外出援助を行います。対象は千葉市内に居住し、妊娠中または出産後1年未満（多胎の場合は出産後1年未満）で、日中に家事・育児を担う人が他にいない世帯とされています。利用は1回2時間・1,680円が基本で、世帯の課税状況等に応じた減免制度があり、利用回数は対象の妊娠・出産につき通算30回まで（多胎の場合は50回まで）とされています。助産師が母子の心身のケアを行う産後ケア事業とは別の事業であることが公式に明記されています。対象条件・利用可能回数・料金は世帯状況により異なる可能性があるため、利用前に千葉市へご確認ください。', '妊娠中や赤ちゃんが生まれてから1年くらいの間、家事や育児を手伝ってくれる人が身近にいないとき、千葉市のヘルパーさんが家に来て、料理・洗濯・掃除やおむつ替え・沐浴などを手伝ってくれる制度です。利用したいときは早めに市へ申し込みます。', 'service', '千葉市内に居住し、(1)妊娠中または出産後1年未満で、昼間に家事または育児を行う者が他にいない世帯、または(2)多胎による出産後1年未満で、当該出産により出生した子を養育する世帯が対象となる可能性があります。利用者本人が自宅にいることが前提とされています。詳細な該当条件は公式ページでご確認ください。', '1回2時間あたり1,680円が基本料金とされています。生活保護世帯・市民税非課税世帯は無料、所得割課税額48,600円未満は250円、ひとり親世帯・多胎世帯は840円など、世帯の課税状況に応じた減免制度がある可能性があります。利用回数は対象の妊娠・出産につき通算30回まで（多胎の場合は50回まで）、1日2回までとされています。正確な料金・回数は世帯状況により異なるため公式で確認してください。', '利用を希望する日の5営業日前まで（閉庁日を除く）に申請が必要とされています。派遣の調整には10日から2週間程度かかる場合があるとされ、利用開始まで余裕を持った申請が必要です。ゴールデンウィークや年末年始は申請期限が変更される可能性があります。', '事前に利用登録（電子申請または申請書提出）を行った上で、利用希望日ごとに利用申請（電子申請・電話・書面等）を行う方法とされています。申請書は各区保健福祉センターまたはこども未来局幼児教育・保育部幼保支援課で配布されているとのことです。詳細な手順は公式ページでご確認ください。', '減免制度を利用する場合は、生活保護受給証明書、課税証明書等の該当を証明する書類が必要とされています。多胎の場合は母子健康手帳の写しなど、該当を確認できる書類の添付が必要とされています。詳細は公式でご確認ください。', TRUE, '千葉市 こども未来局 幼児教育・保育部 幼保支援課', '043-245-5180', NULL, 'https://www.city.chiba.jp/kodomomirai/yojikyoiku/shien/engel2.html', '千葉市：エンゼルヘルパーのご案内', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '対象条件・利用できる回数・利用料は世帯状況や市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず千葉市の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
