insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"chiba-chiba-prenatal-postpartum-helper","status":"published","title":"エンゼルヘルパー派遣事業","officialUrl":"https://www.city.chiba.jp/kodomomirai/yojikyoiku/shien/engel2.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:chiba-chiba-prenatal-postpartum-helper:Y2hpYmEtY2hpYmEtcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8QVRvQ1VmK2lSMmVaL0N1UHo0bzQ1c2hV' from public.support_programs sp where sp.slug='chiba-chiba-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'fukuoka'), 'fukuoka-fukuoka-prenatal-postpartum-helper', '福岡市産前・産後ヘルパー派遣事業', '福岡市が実施する産前・産後ヘルパー派遣事業です。日中、家族などから家事や育児の支援を受けることが難しい妊産婦・子育て家庭に、市が委託した事業者からヘルパーを派遣し、家事（掃除・洗濯・買い物など）や育児（授乳の手伝い・沐浴の補助・上の子の世話など）を手伝うことで、育児不安や負担の軽減を図る事業とされています。対象は福岡市内に住民票があり、妊娠中または生後1年未満の赤ちゃんがいる方で、1回2時間以内・1日2回まで、妊娠中は最大10回、産後は最大20回（第2子以降で未就学のきょうだいがいる場合は40回、多胎児世帯は外出支援20回を含め60回）まで利用できる可能性があると公式サイトに記載されています。利用料は1回500円が基本で、生活保護世帯・市民税非課税世帯は免除される可能性があるとされ、別途交通費実費（上限500円）がかかります。福岡市が別に実施する産後ケア事業（助産師等による宿泊型・日帰り型・訪問型の母子の心身ケア）とは異なる事業であり、本制度は家事・育児の手伝いを行うヘルパー派遣が中心です。対象や利用回数・料金の詳細は世帯状況により異なる可能性があるため、利用前に福岡市へ確認してください。', '妊娠中や赤ちゃんが生まれてから1年未満で、日中に家族から家事や育児を手伝ってもらえないとき、福岡市が委託したヘルパーが家に来て家事や育児を手伝ってくれる制度です。1回500円程度からの利用料と交通費がかかります。利用したいときは福岡市が委託した事業者へ直接申し込みます。', 'service', '福岡市内に住民票があり、妊娠中または生後1年未満の赤ちゃんがいる方で、日中、家族等から家事や育児の支援を受けることが難しい方が対象となる可能性があります。多胎児（双子・三つ子等）世帯向けの外出支援は多胎児世帯のみが対象とされています。', '1回2時間以内・1日2回まで利用できる可能性があります。回数の上限は妊娠中は最大10回、産後は最大20回（第2子以降で未就学のきょうだいがいる場合は40回、多胎児世帯は外出支援20回を含め60回）とされています。利用料は1回500円が基本で、生活保護受給世帯・市民税非課税世帯は保護受給証明書または非課税証明書の提示により免除される可能性があります。別途、ヘルパー派遣にかかる交通費実費相当額（上限500円）が必要です。', NULL, '公式ページでは「産前・産後ヘルパー派遣事業の内容など、詳細については、直接事業者へお問い合わせ下さい」とされており、福岡市が公表する受託事業者一覧の中から事業者を選び、直接申し込む方式とみられます。', '利用登録申込書（様式第1号）、利用登録変更届（様式第3号）、利用申込書（様式第5号）が公式サイトで提供されています。減免を希望する場合は生活保護受給証明書または市民税非課税証明書等が必要になる可能性があります。', FALSE, '福岡市こども未来局こども健やか部こども健やか課', '092-711-4065', 'https://www.city.fukuoka.lg.jp/kodomo-mirai/k-sukoyaka/child/sangohelper.html', 'https://www.city.fukuoka.lg.jp/kodomo-mirai/k-sukoyaka/child/sangohelper.html', '福岡市 福岡市産前・産後ヘルパー派遣事業のご案内', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'applicationMethodText', 'onlineApplicationAvailable', 'requiredDocumentsText']::text[], '対象条件・利用できる回数や時間・利用料は世帯状況や福岡市の認定・委託事業者の運用により異なる場合があります。本ページは概要であり、最新かつ正確な情報は必ず福岡市の公式サイトおよび窓口（こども健やか課）でご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
