insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"fukuoka-fukuoka-prenatal-postpartum-helper","status":"review","title":"福岡市産前・産後ヘルパー派遣事業","officialUrl":"https://www.city.fukuoka.lg.jp/kodomo-mirai/k-sukoyaka/child/sangohelper.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:fukuoka-fukuoka-prenatal-postpartum-helper:ZnVrdW9rYS1mdWt1b2thLXByZW5hdGFsLXBvc3RwYXJ0dW0taGVscGVyfHVWSnpFV1ZuQ2VDV3RDNkpwRm9FOTRFNA==' from public.support_programs sp where sp.slug='fukuoka-fukuoka-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'kitakyushu'), 'fukuoka-kitakyushu-prenatal-postpartum-helper', '産前産後子育て支援ヘルパー派遣事業', '北九州市が実施する産前産後子育て支援ヘルパー派遣事業です。日中、家族等から家事や育児の援助が受けられない家庭にヘルパーを派遣し、家事（食事の準備、洗濯、居室の掃除等）や育児（授乳・おむつ交換・沐浴の手伝い等）を援助することで、育児不安や負担の軽減、家庭や地域での孤立感の解消を図るとされています。対象となる可能性があるのは、北九州市内に住民票があり、日中に家族等からの支援が受けられない、1歳未満の子どもがいる方、3歳未満の子どもが二人以上（多胎児含む）いる方、妊娠中で体調不良の方、流産・死産から1年以内で体調不良の方です。利用は1回2時間以内・1日2回まで、期間中最大20回（多胎児等は40回）とされ、利用料は1時間あたり1,000円ですが、生活保護世帯・市民税非課税世帯には減免制度があるとされています。なお、助産師等による母子の心身ケアを行う「産後ケア事業」（宿泊型・通所型・訪問型）とは別の事業であり、本ページで扱うのは家事・育児支援ヘルパーの派遣に限られます。市には別途、要支援認定世帯向けの「子育て世帯訪問支援事業」もありますが、対象要件が異なるため、利用にあたっては公式サイトで対象事業を確認してください。', '妊娠中や産後、小さい子どもがいる家庭で、家族から家事や育児の手伝いを受けられないとき、北九州市のヘルパーが家に来て家事や育児を手伝ってくれる制度です。利用したいときは「きたきゅう子育て応援アプリ」から申し込むか、事業所に電話で予約します。', 'service', '北九州市内に住民票があり、日中、家族等から家事や育児の支援が受けられない方のうち、1歳未満の子どもがいる方、3歳未満の子どもが二人以上（多胎児含む）いる方、妊娠中で体調不良の方、または流産・死産から1年以内で体調不良の方が対象となる可能性があります。詳しい認定基準は市の窓口での確認が必要です。', '1回2時間以内・1日2回まで利用でき、利用できる期間中に最大20回まで（3歳未満の子どもが二人以上いる方・多胎児家庭は40回まで）とされています。利用時間は午前8時から午後6時まで（年末年始12月29日～1月3日を除く）。利用料は1時間あたり1,000円に加えて交通費実費相当額（事業所による）が必要とされていますが、生活保護世帯・市民税非課税世帯には減免制度があるとされています。', '公式ページに明確な申請期限の記載は確認できませんでした。利用を希望する時期に応じて早めの申請が望ましいと考えられます。正確な受付期間・利用開始までの日数は市の窓口で確認してください。', '「きたきゅう子育て応援アプリ」から事前に申請するか、アプリを利用しない場合は希望する事業所に直接電話して予約する方法があるとされています。', '利用時に母子健康手帳、健康保険証、北九州市子ども医療証の提示が必要とされています。利用料の減免を申請する場合は、生活保護受給証明書または市民税非課税証明書の写しが必要とされています。', TRUE, '北九州市子ども家庭局子育て支援部子育て支援課 母子保健係', '093-582-2082', NULL, 'https://www.city.kitakyushu.lg.jp/contents/11700376.html', '産前産後子育て支援ヘルパー派遣事業のご案内 - 北九州市', '2026-07-01', 'high', ARRAY['applicationDeadlineText']::text[], '対象条件・利用できる回数や時間・利用料は世帯状況や市の認定により異なる場合があります。本ページは概要であり、最新かつ正確な情報は必ず北九州市の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
