insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"fukuoka-kitakyushu-prenatal-postpartum-helper","status":"published","title":"産前産後子育て支援ヘルパー派遣事業","officialUrl":"https://www.city.kitakyushu.lg.jp/contents/11700376.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:fukuoka-kitakyushu-prenatal-postpartum-helper:ZnVrdW9rYS1raXRha3l1c2h1LXByZW5hdGFsLXBvc3RwYXJ0dW0taGVscGVyfFlONnMzK3FkWGUrUmpwa0ZSTzB6MEVwSg==' from public.support_programs sp where sp.slug='fukuoka-kitakyushu-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hiroshima' and m.slug = 'hiroshima'), 'hiroshima-hiroshima-prenatal-postpartum-helper', '広島市産後ヘルパー派遣事業', '広島市が実施する産後ヘルパー派遣事業です。出産後に体調不良や育児不安等があり、家族から家事・育児の支援を十分に受けられない産後1年未満の母親と乳児の家庭に、ヘルパーを派遣して家事（食事の準備・後片付け、洗濯・衣類の補修、掃除・整理整頓、生活必需品の買い物など）や育児（授乳の介助、おむつ・衣類の交換、沐浴の介助、兄姉児の世話など）を支援します。多胎児を出産した場合も対象に含まれるとされています。申請自体は概ね妊娠8か月（28週）以降から可能ですが、実際にサービスを利用できるのは産後（母親と生後1年未満の乳児）に限られるとされています。広島市が別に実施する産後ケア事業（助産師等による母体の回復支援・乳房管理・育児指導などの医療的ケア、宿泊型・通所型・訪問型）とは別の事業であり、また会員同士の相互援助であるファミリー・サポート・センターとも異なる、市が委託事業者を通じて直接ヘルパーを派遣する制度とされています。ヘルパーが一人で子どもの世話をすることはできないとの注記もあります。', '赤ちゃんが生まれたあと、体調がすぐれなかったり育児に不安があったりして、家族の助けも十分に受けられないとき、広島市がヘルパーを家に派遣して、家事や育児のお手伝いをしてくれる制度です。申請は妊娠8か月ごろからできます。早めに区の窓口に相談することがすすめられています。', 'service', '広島市在住で、産後に体調不良や育児不安等があり（多胎児を出産した方を含む）、家族からの家事・育児支援が十分に受けられない、産後1年未満の母親と乳児の家庭が対象となる可能性があります。申請自体は概ね妊娠8か月（28週）以降から可能とされていますが、最終的な利用可否は区の保健師による面接・訪問での確認を経て判断されるとされています。', '市民税課税世帯は1時間500円、1時間30分750円、2時間1,000円。市民税非課税世帯または生活保護世帯は無料とされています。令和9年3月31日まで利用料金の半額が補助されるとされています。利用回数は1日2回まで、単胎児は延べ10回、多胎児は延べ20回が目安とされています（正確な料金・回数は公式ページでご確認ください）。', '概ね妊娠8か月（28週）以降から申請可能とされています。具体的な申請から利用開始までの所要期間の明記はありませんが、「調整に時間がかかる場合があるので、お早めにご相談ください」との注記があります。', '各区の地域支えあい課（こども家庭センター）に連絡のうえ、保健師による面接・家庭訪問を経て申請する流れとされています。', '申請書に加え、生活保護世帯の場合は被保護者証明書、市民税非課税世帯の場合は課税台帳証明などの所得関係書類が必要になる場合があるとされています（詳細は窓口でご確認ください）。', FALSE, '広島市こども未来局こども青少年支援部　母子保健担当（または各区地域支えあい課・こども家庭センター）', '082-504-2623', NULL, 'https://www.city.hiroshima.lg.jp/living/kosodate/1021253/1025913/1038835.html', '広島市産後ヘルパー派遣事業｜広島市公式ウェブサイト', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '対象条件・利用できる時間や回数・利用料は世帯状況や広島市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず広島市の公式サイトおよび各区地域支えあい課（こども家庭センター）でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
