insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"hiroshima-hiroshima-prenatal-postpartum-helper","status":"published","title":"広島市産後ヘルパー派遣事業","officialUrl":"https://www.city.hiroshima.lg.jp/living/kosodate/1021253/1025913/1038835.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:hiroshima-hiroshima-prenatal-postpartum-helper:aGlyb3NoaW1hLWhpcm9zaGltYS1wcmVuYXRhbC1wb3N0cGFydHVtLWhlbHBlcnxqb2kvZUJMbi9MS1BQQjhIL0VxUHRTMGY=' from public.support_programs sp where sp.slug='hiroshima-hiroshima-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hyogo' and m.slug = 'kobe'), 'hyogo-kobe-prenatal-postpartum-helper', '産前産後ホームヘルプサービス', '神戸市が実施する産前産後ホームヘルプサービスです。妊娠中や出産後の家庭で、体調不良などのため家事や育児が困難であり、かつ昼間に手伝ってくれる人がいない場合に、神戸市が契約する事業者からヘルパーが派遣され、食事の準備や片づけ、洗濯、生活必需品の買い物、おむつ交換や上の子の世話など、日常的に行っている家事・育児の支援を受けられる可能性があるとされています。産前は10回まで、産後は出産後2年以内（お子さんの2歳の誕生日の前日まで）に20回まで、1回連続2時間以内（外出を伴う場合は1日2回・4時間まで）利用できる可能性があると公式に記載されています。神戸市が別に実施する産後ケア事業（宿泊型・通所型・訪問型、助産師等による母子の心身のケア）や多胎児家庭ホームヘルプサービスとは異なる、別の事業として案内されています。対象となるかどうかや利用可能な事業者はお住まいの区によって異なるため、利用前に神戸市へ確認してください。', '妊娠中や産後で、体調が悪くて家事や育児が大変なのに、手伝ってくれる人が近くにいないとき、神戸市と契約したヘルパーが家に来て、食事の準備や洗濯、おむつ替えなどを手伝ってくれる制度です。利用したいときは早めにe-KOBEか区役所に申し込みます。', 'service', '神戸市内在住で、(1)妊娠中に体調不良などのため家事や育児が困難で、昼間手伝ってくれる人がいない方（産前・10回まで）、または(2)出産後2年以内（お子さんの2歳の誕生日の前日まで）で、体調不良などのため家事や育児が困難で、昼間手伝ってくれる人がいない養育者（産後・20回まで）が対象となる可能性があります。ヘルパーが対応できるのは、妊婦や養育者が日常的に行っている家事・育児の範囲に限られるとされています。', '1回（連続2時間以内）あたり1,600円。市県民税非課税世帯および生活保護受給世帯は自己負担なしとされています。キャンセル料は1回あたり800円。利用可能日は月曜～土曜（祝日・年末年始を除く）の9時～18時で、産前は10回まで、産後は20回まで利用できる可能性があります（外出を伴う場合は1日2回・連続4時間まで）。', '明確な申請期限の記載は確認できませんでした。利用を希望する期間の前に余裕をもって申請する必要があると考えられます。詳細は公式サイトまたは区役所でご確認ください。', 'e-KOBE（神戸市スマート申請システム）の「産前産後ホームヘルプサービス事業の利用申請」から申請できます。e-KOBEでの申請が難しい場合は、お住まいの区の区役所・支所保健福祉課へ相談することもできるとされています。申請後、区役所・支所から「派遣決定通知書」が送付され、申請者と契約事業者の間で利用日時を調整してサービスが開始される流れです。', '市県民税非課税世帯の場合は世帯全員分の「市県民税非課税証明書」、生活保護受給世帯の場合は「生活保護適用証明書」が必要とされています。それ以外の世帯で必要な書類については明記が確認できませんでした。', TRUE, '神戸市 こども家庭局家庭支援課（または、お住まいの区役所・支所 保健福祉課）', '', 'https://www.city.kobe.lg.jp/a86732/kosodate/maternity/consult/sanzensango/index.html', 'https://www.city.kobe.lg.jp/a86732/kosodate/maternity/consult/sanzensango/index.html', '産前産後ホームヘルプサービス - 神戸市', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'contactPhone', 'requiredDocumentsText（非課税・生活保護以外の世帯分）']::text[], '対象条件・利用できる回数や時間・利用料・利用可能な事業者はお住まいの区や世帯状況、神戸市の認定により異なる場合があります。本ページは概要であり、最新かつ正確な情報は必ず神戸市の公式サイトおよびお住まいの区役所・支所保健福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
