insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'kawasaki'), 'kanagawa-kawasaki-prenatal-postpartum-helper', '産前・産後家庭支援ヘルパー派遣事業', '川崎市が実施する産前・産後家庭支援ヘルパー派遣事業です。市内に居住する産前から産後6か月（多胎児の妊産婦は産後1年を迎える日まで）の妊産婦で、休息が必要な時や体調不良等により育児や家事が困難であり、かつ昼間他に育児や家事を行う人がいない家庭に、認定を受けた事業者のヘルパーが訪問し、育児や家事の支援を行います。原則として母親が自宅にいる状態での支援を想定しており、単なる子どもの預かりとは異なります。利用時間は多胎児以外は40時間、多胎児は120時間まで（1日4時間以内、1日2回まで）利用できる可能性があると公式に案内されています。助産師等が行う産後ケア事業とは別の事業です。対象や利用料・利用時間は世帯状況や認定内容により異なるため、利用前に川崎市へ確認してください。', '妊娠中や出産後、家事や育児を手伝ってくれる人が身近にいないとき、川崎市が認定した事業者のヘルパーが家に来て家事や育児を手伝ってくれる制度です。利用したい日の7日前までに事業者へ申し込みます。', 'service', '川崎市内に居住する産前から産後6か月（多胎児の場合は産後1年を迎える日まで）の妊産婦で、体を休めたい時や体調不良等があり、昼間他に育児や家事を行う人がいない場合に対象となる可能性があります。', '通常は最大40時間、多胎児家庭は最大120時間まで利用できるとされています（1日4時間以内、1日2回まで）。利用料金は1時間あたり800円が基本とされ、別途各事業者が定める交通費がかかる場合があります。生活保護受給世帯・世帯全員が市民税非課税の世帯は減免措置がある可能性があります。詳細は公式ページでご確認ください。', '原則としてヘルパー派遣開始希望日の7日前までに、選んだ認定事業者へ直接申請する必要があるとされています。', '「川崎市産前・産後家庭支援ヘルパー派遣事業認定事業者一覧」から事業者を選び、利用者が事業者へ直接申し込みます。', '利用申請書（第9号様式）、利用日程申請書兼確認書（第9号様式の2）。利用料の減免を希望する場合は被保護証明書または非課税証明書が必要とされています。', FALSE, 'こども未来局 児童家庭支援・虐待対策室 母子保健担当', '044-200-2450', NULL, 'https://www.city.kawasaki.jp/450/page/0000030633.html', '川崎市：産前・産後家庭支援ヘルパー派遣事業', '2026-07-01', 'high', ARRAY['onlineApplicationAvailable（一部事業者はホームページ申込フォーム対応の可能性あり、市全体としての可否は要確認）']::text[], '対象条件・利用できる時間・利用料は世帯状況や認定内容、選ぶ事業者により異なります。本ページは概要であり、最新かつ正確な情報は必ず川崎市の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
