insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"kanagawa-kawasaki-prenatal-postpartum-helper","status":"published","title":"産前・産後家庭支援ヘルパー派遣事業","officialUrl":"https://www.city.kawasaki.jp/450/page/0000030633.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:kanagawa-kawasaki-prenatal-postpartum-helper:a2FuYWdhd2Eta2F3YXNha2ktcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8Z1NKdW44NGJtZlN5WElSLzE2QzMybThi' from public.support_programs sp where sp.slug='kanagawa-kawasaki-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'sagamihara'), 'kanagawa-sagamihara-prenatal-postpartum-helper', '子育て世帯訪問支援事業', '相模原市が実施する子育て世帯訪問支援事業です。出生後1年以内の乳児や多胎児と同居し養育している世帯で、心身の不調等により家事が困難、または家事を行う他の家族がいない等の理由で支援が必要な場合に、家事支援事業者が自宅を訪問し、食事の準備・後片付け、衣類の洗濯・補修、居室等の掃除整理整頓、生活必需品の買い物などの家事支援を行います。この事業はヤングケアラーのいる世帯への家事支援も同じ枠組みで扱っており、対象は「産後（出生後1年以内）」の家庭であり、妊娠中（産前）の家庭は対象に含まれていない点に注意が必要です。助産師等による産後ケア事業や、会員同士が援助し合うファミリー・サポート・センター事業とは別の事業です。対象や利用回数・料金は世帯状況により異なるため、利用前に相模原市へ確認してください。', '生まれたばかりの赤ちゃんがいる家庭や双子・三つ子などのいる家庭で、家事をする人が身近にいなかったり体調がすぐれなかったりするとき、相模原市の家事支援の人が家に来て、食事の準備や洗濯、掃除、買い物などを手伝ってくれる制度です。妊娠中は対象外で、出産後に利用できます。', 'service', '相模原市に住民登録があり、出生後1年以内の乳児と同居し養育している人（心身の不調等により家事が困難、または家事を行う他の家族がいない等の理由で支援が必要な人）、または出生後1年以内の多胎児と同居し養育している人が対象となる可能性があります。妊娠中（産前）は対象に含まれていません。', '基本利用料金は1回2時間あたり6,300円とされ、乳児・多胎児のいる世帯の自己負担は1回1,800円（市民税非課税世帯は900円、生活保護世帯は0円）とされています。利用回数の上限は乳児のいる世帯で20回、多胎児のいる世帯で30回とされていますが、詳細な期間の定めは公式ページで要確認です。', '公式ページに具体的な申請期限（利用開始までの必要日数）の明記は確認できませんでした。事前の利用申請が必要とされています。', '利用申請書兼同意書等を、こども家庭課または各区の子育て支援センター等へ窓口持参または郵送で提出するとされています。', '利用申請書兼同意書、世帯調書。減免を希望する場合は所得証明書類等が必要とされる可能性があります。', FALSE, 'こども家庭課（保健事業班）', '042-769-8345', NULL, 'https://www.city.sagamihara.kanagawa.jp/kosodate/1026602/kosodate/1025906.html', '子育て世帯訪問支援事業｜相模原市', '2026-07-01', 'medium', ARRAY['applicationDeadlineText（申請から利用開始までの必要日数が公式ページ本文で確認できなかった）', 'benefitAmountText（利用回数上限の対象期間の区切り方が要確認）', 'requiredDocumentsText（詳細な必要書類の記載が薄い）']::text[], '対象条件・利用できる回数・利用料は世帯状況や市の認定により異なります。特にこの事業は「産後（出生後1年以内）」のみが対象で、妊娠中の「産前」は対象外です。本ページは概要であり、最新かつ正確な情報は必ず相模原市の公式サイトおよび窓口でご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
