insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'yokohama'), 'kanagawa-yokohama-prenatal-postpartum-helper', '産前産後ヘルパー派遣事業', '横浜市が実施する産前産後ヘルパー派遣事業です。妊娠中に心身の不調等があり日中の家事や育児を行う人が他にいない世帯、または出産後5か月未満（多胎児は出産後1年未満）で同様に支援が必要な世帯に対して、市が委託した事業者からヘルパーが派遣され、家事支援（食事の準備・後片づけ、洗濯、掃除等）と育児支援（授乳介助、おむつ交換、沐浴介助等）を行うとされています。育児支援は保護者と児童が一緒にいる場面での実施が前提とされ、ヘルパーが児童だけを預かることはできないとされています。利用は産前・産後それぞれ20回以内（多胎児の場合は産後40回以内）、1回2時間以内・1日2回までとされ、利用料は1回1,500円で減免制度もあるとされています。横浜市が別に実施する「産後母子ケア事業」（助産師等による母体管理や授乳指導などの専門的ケア）とは異なる事業であり、本事業は家事・育児の実務的な支援が中心です。対象要件や利用可否の詳細は世帯の状況により異なるため、利用前に横浜市（各区こども家庭支援課）へ確認することが必要です。', '妊娠中や出産後に、家事や育児を手伝ってくれる人が身近にいないとき、横浜市が委託したヘルパーが自宅に来て、食事の準備や掃除、洗濯、授乳やおむつ替えなどを手伝ってくれる制度です。利用したいときは、早めにお住まいの区のこども家庭支援課に相談します。', 'service', '横浜市内に住民登録がある世帯のうち、(1)妊娠中で心身の不調等があり日中に家事・育児を行う人が他にいない世帯、または(2)出産後5か月未満（多胎児の場合は出産後1年未満）で同様に日中の家事・育児を行う人が他にいない世帯が対象となる可能性があります。早産等でお子さんが入院している場合も相談可能とされています。世帯の状況によって利用の可否は異なるため、区の窓口で確認することが必要です。', '利用料は1回（2時間以内）1,500円とされ、世帯の課税状況等により減免制度がある可能性があります（生活保護世帯・市町村民税非課税世帯は無料、一定の所得基準以下は500円等）。利用できる回数は産前・産後それぞれ20回以内（多胎児の場合は産後40回以内）、利用時間は月曜〜金曜（年末年始・祝日を除く）9時〜17時の間で1回2時間以内・1日2回までとされています。詳細な料金・減免条件は区の窓口で確認してください。', 'サービス利用開始を希望する日の7日前（閉庁日を除く）までに区のこども家庭支援課へ申請する必要があるとされています。また、利用を希望する日の3日前17時までに派遣事業者へ直接連絡し、対応可否を確認する必要があるとされています。', 'まず利用したい派遣事業者（複数の委託事業者から選択）に電話等で連絡し、ヘルパー派遣が可能か確認します。その後、居住区のこども家庭支援課の窓口で「横浜市産前産後ヘルパー利用（登録）申請書（第1号様式）」を記入し、面接のうえ申請します。郵送での申請は不可とされています。', '産前産後ヘルパー利用（登録）申請書（第1号様式）。妊娠中の利用の場合は診療情報提供書、または母子健康手帳の該当ページ（P80・81等）の写し。転入等で世帯の課税状況が確認できない場合は世帯全員分の課税状況を証明する書類が必要になる可能性があります。', FALSE, '横浜市こども青少年局こども福祉保健部地域子育て支援課', '045-671-2455', NULL, 'https://www.city.yokohama.lg.jp/kosodate-kyoiku/oyakokenko/ninshin/sanzensango.html', '産前産後ヘルパー派遣事業　横浜市', '2026-07-01', 'high', ARRAY['benefitAmountText（減免の具体的な所得基準等は本ページに完全には記載なし）']::text[], '対象条件・利用できる回数や時間・利用料（減免を含む）は世帯の状況や区の判断により異なる可能性があります。本ページは概要であり、最新かつ正確な情報は必ず横浜市の公式サイトおよびお住まいの区のこども家庭支援課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
