insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"kanagawa-yokohama-prenatal-postpartum-helper","status":"published","title":"産前産後ヘルパー派遣事業","officialUrl":"https://www.city.yokohama.lg.jp/kosodate-kyoiku/oyakokenko/ninshin/sanzensango.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:kanagawa-yokohama-prenatal-postpartum-helper:a2FuYWdhd2EteW9rb2hhbWEtcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8YWJqaFpUTmVPby82T3JZWGRiUVFMOWs0' from public.support_programs sp where sp.slug='kanagawa-yokohama-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kumamoto' and m.slug = 'kumamoto'), 'kumamoto-kumamoto-prenatal-postpartum-helper', '産前産後ホームヘルプサービス事業', '熊本市が実施する産前産後ホームヘルプサービス事業です。妊娠中または出産後に体調不良等がある場合や、多胎出産で家事や育児を行うことが困難な家庭に、ホームヘルパーを派遣し、妊産婦や乳児の身のまわりの世話・育児等を支援することで、育児不安や育児・家事の負担を軽減し、児童及びその家庭の福祉の向上を図ることを目的としています。登録決定日から出産後1年未満まで利用でき、原則として年末年始を除く毎日、午前8時から午後6時の間で1時間・2時間・3時間から選択し、40回まで利用できるとされています。利用料金は1時間につき600円で、生活保護受給者は免除される可能性があると公式に記載されています。熊本市が別に実施する産後ケア事業（助産師等の専門職による母子の心身のケア）とは異なる事業であり、公式サイト上でも別ページで案内されています。対象や利用条件の詳細は世帯状況により異なるため、利用前に熊本市へ確認してください。', '妊娠中や出産後に、体調がすぐれず家事や育児が難しいとき、熊本市のホームヘルパーが家に来て、身の回りの世話や育児を手伝ってくれる制度です。1時間600円程度で、40回まで利用できる可能性があります。利用したいときは早めにお住まいの区役所へ相談してください。', 'service', '熊本市内に住み、親子（母子）健康手帳の交付を受けている妊婦の方、または出産後1年未満の乳児を養育する方であって、体調不良等により家事や育児を行うことが困難であり、かつ昼間に家事や育児を行う方が他にいない場合に対象となる可能性があります。また、親子（母子）健康手帳の交付を受けている多胎妊婦の方、または多胎出産して1年未満の方も対象となる可能性があります。詳細な要件は各区役所へご確認ください。', '利用料金は1時間につき600円とされています。1回あたり1時間・2時間・3時間から選択でき、登録決定日から出産後1年未満まで、合計40回まで利用できるとされています。生活保護受給世帯は利用料金が免除される可能性があります。利用可能時間帯は原則として午前8時から午後6時まで、年末年始（12月29日〜1月3日）を除く毎日とされています。', '明確な申請期限の記載は確認できませんでした。妊娠中は母子健康手帳取得後から、出産後も登録申請が可能とされています。', 'お住まいの区の区役所保健こども課健康増進班の窓口で登録申請書を提出するか、登録申請書に記入のうえ郵送する方法があるとされています。窓口・郵送先は区ごとに異なります。', '登録申請書（ワード・PDF形式で公式サイトに様式あり）が必要とされています。内容変更や利用を辞退する場合は、変更・辞退届の提出が必要とされています。', FALSE, '熊本市 各区役所保健こども課健康増進班（登録・利用について）／熊本市こども局こども育成部こども支援課（制度全般について）', '096-328-2419', NULL, 'https://www.city.kumamoto.jp/kiji003517/index.html', '産前産後ホームヘルプサービス事業について / 熊本市公式サイト', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'onlineApplicationAvailable', '生活保護受給世帯以外の減免措置の有無']::text[], '対象条件・利用できる時間や回数・利用料は世帯状況や熊本市の認定により異なる場合があります。本ページは概要であり、最新かつ正確な情報は必ず熊本市の公式サイトおよびお住まいの区の区役所保健こども課窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
