insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"kumamoto-kumamoto-prenatal-postpartum-helper","status":"published","title":"産前産後ホームヘルプサービス事業","officialUrl":"https://www.city.kumamoto.jp/kiji003517/index.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:kumamoto-kumamoto-prenatal-postpartum-helper:a3VtYW1vdG8ta3VtYW1vdG8tcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8VnNzM1lkWEdzdGlHNGNOeEwzM2FpMjY0' from public.support_programs sp where sp.slug='kumamoto-kumamoto-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kyoto' and m.slug = 'kyoto'), 'kyoto-kyoto-prenatal-postpartum-helper', '第三子以降及び多胎の出産をサポート！産前産後ヘルパー派遣事業', '京都市が実施する産前産後ヘルパー派遣事業です。小学生以下の子どもが3人以上（産前は2人以上）いる世帯で第三子以降の子どもを妊娠・出産する場合、または多胎児を妊娠・出産する場合に、家事や育児を行うことが困難で他に適切に対応できる人がいない家庭へヘルパーを派遣し、家事（食事準備・洗濯・掃除・買い物等）や育児（授乳・おむつ交換・沐浴の補助等）を援助するとされています。派遣は1日1回30分単位で最大2時間まで、第三子以降は16回以内、多胎児は32回以内利用できる可能性があると公式に記載されています。利用料金は生活保護世帯・市民税非課税世帯は無料、それ以外は30分400円から2時間1,600円までの区分となっています。なお、京都市には対象をより広く産後うつ・育児不安等の要支援家庭とする「育児支援ヘルパー派遣事業」も別途あり、この産前産後ヘルパー派遣事業とは別の申請区分とされています。また、助産師等による母子の心身のケアを行う「京都市スマイルママ・ホッと事業（産後ケア事業）」とは異なる事業です。対象要件・利用可能時間・料金は世帯状況により異なるため、利用前に京都市へ確認してください。', '3人目以降の赤ちゃんや双子・三つ子などを妊娠・出産する家庭で、家事や育児を手伝ってくれる人が身近にいないとき、京都市のヘルパーが家に来て家事や育児を手伝ってくれる制度です。利用したいときは早めにお住まいの区役所に相談します。', 'service', '京都市に住民票があり、小学生以下の子どもが3人以上（妊娠中の場合は2人以上）いる世帯で第三子以降の子どもを妊娠中または出産後の方、または多胎児を妊娠中または出産後の方が対象となる可能性があります。家事や育児を行うことが困難で、家族等ほかに適切に対応できる方がいない場合が対象とされています。産後うつ・育児不安等を理由とする場合は対象がより広い「育児支援ヘルパー派遣事業」に該当する可能性があるため、区役所の窓口で確認することが推奨されます。', '利用料金は世帯区分により、生活保護受給世帯・市民税非課税世帯は無料、それ以外の世帯は30分以内400円、1時間以内800円、1時間30分以内1,200円、2時間以内1,600円とされています。派遣は1日1回・30分単位で最大2時間まで、利用回数は第三子以降の場合16回以内、多胎児の場合32回以内とされています。', '申請受付は、派遣を希望する月の2か月前から可能とされています。ヘルパーの手配状況によって調整に時間がかかる場合があるとの記載があるため、早めの相談が推奨されます。明確な申請締切日の定めは公式ページ上には確認できませんでした。', 'お住まいの地域の区役所・支所子どもはぐくみ室子育て相談担当（京北出張所管内は同出張所保健福祉第一担当）へ申し込むとされています。2026年4月1日から、従来の窓口申請に加えてオンラインによる申請受付も開始されたと公式に記載されています。オンライン申請を希望する場合も、まずは各区役所・支所へ相談することが案内されています。', '利用申請書（第1号様式）、世帯全員の住民票等（住所・世帯構成が確認できるもの）が必要とされています。生活保護世帯の場合は生活保護受給証明書、市民税非課税世帯の場合は世帯全員分の非課税証明書（利用年度分）が必要とされていますが、申請書の調査同意欄に同意することで一部書類の提出を省略できる場合があるとされています。', TRUE, '京都市子ども若者はぐくみ局子ども若者未来部子ども家庭支援課（申込は各区役所・支所子どもはぐくみ室）', '075-222-3939', NULL, 'https://www.city.kyoto.lg.jp/hagukumi/page/0000206563.html', '京都市：第三子以降及び多胎の出産をサポート！産前産後ヘルパー派遣事業', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'onlineApplicationAvailable']::text[], '対象条件・利用できる時間や回数・利用料は世帯状況や京都市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず京都市の公式サイトおよびお住まいの区役所・支所子どもはぐくみ室でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
