insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"kyoto-kyoto-prenatal-postpartum-helper","status":"published","title":"第三子以降及び多胎の出産をサポート！産前産後ヘルパー派遣事業","officialUrl":"https://www.city.kyoto.lg.jp/hagukumi/page/0000206563.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:kyoto-kyoto-prenatal-postpartum-helper:a3lvdG8ta3lvdG8tcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8eHNSbUtoaUdUeGwyQktOekNSL1NIRWUz' from public.support_programs sp where sp.slug='kyoto-kyoto-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'miyagi' and m.slug = 'sendai'), 'miyagi-sendai-prenatal-postpartum-helper', '子育て世帯訪問支援事業（育児ヘルパー派遣）', '仙台市が実施する子育て世帯訪問支援事業（育児ヘルパー派遣）です。妊娠中から出産後1年以内の期間に、体調不良などのため家事や育児が困難になっている家庭、または小児慢性特定疾病の認定を受けている児童がいる家庭に対し、ヘルパーが自宅を訪問して家事（食事の準備・後片付け、住居の掃除、生活必需品の買い物など）や育児（授乳・おむつ交換・沐浴のお手伝いなど）を支援します。利用は妊娠中から出産後1年以内の期間で20回以内（多胎児の場合は30回以内）、1日1回・1回2時間まで（1時間単位、午前9時〜午後6時）利用できるとされています。大掃除・引っ越し作業・除草などは対象外とされています。仙台市が実施する産後ケア事業（助産師等による母体回復のためのケアや育児指導など）とは別の事業であり、公式サイト上でも別ページとして案内されています。対象条件や利用できる回数・時間、料金は世帯状況により異なる可能性があるため、利用前に仙台市へ確認してください。', '妊娠中や産後1年以内で、体調が悪くて家事や育児が大変なとき、仙台市のヘルパーが家に来て家事や育児を手伝ってくれる制度です。利用したいときはお住まいの区役所家庭健康課に早めに申し込みます。', 'service', '仙台市内に住所があり、妊娠中から出産後1年以内で、体調不良などのため家事や育児が困難な家庭、または小児慢性特定疾病の認定を受けている児童がいる家庭が対象となる可能性があります。詳細な認定基準は区役所家庭健康課での確認が必要です。', '利用できる期間は妊娠中から出産後1年以内で20回以内（多胎児の場合は30回以内）。1日1回、1回につき2時間まで（1時間単位）、利用時間帯は午前9時〜午後6時とされています。利用料金は1時間あたり600円で、所得の状況に応じて減額される場合があるとされています。キャンセル料は1回600円とされています。12月29日〜1月3日は休業期間です。', '原則として利用希望日の2週間前までに申し込みが必要とされています。', 'お住まいの区の区役所家庭健康課または総合支所保健福祉課の窓口に申請書を提出する方法のほか、LoGoフォームによる電子申請も案内されています。', '「仙台市子育て世帯訪問支援事業利用申請書」（公式サイトでPDF様式が配布されています）。', TRUE, '仙台市こども若者局子育て安心課（申請窓口は各区役所家庭健康課・総合支所保健福祉課）', '022-214-7023', 'https://logoform.jp/form/3PrJ/776976', 'https://www.city.sendai.jp/kodomo-chiiki/kurashi/kenkotofukushi/kosodate/azukari/shien/help.html', '子育て世帯訪問支援事業（育児ヘルパー派遣）｜仙台市', '2026-07-01', 'high', ARRAY['targetPeople（体調不良等の具体的な認定基準の詳細）', 'benefitAmountText（所得に応じた減額の具体的な基準額）']::text[], '対象条件・利用できる回数や時間・利用料は世帯状況や区の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず仙台市の公式サイトおよび各区役所家庭健康課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
