insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"miyagi-sendai-prenatal-postpartum-helper","status":"published","title":"子育て世帯訪問支援事業（育児ヘルパー派遣）","officialUrl":"https://www.city.sendai.jp/kodomo-chiiki/kurashi/kenkotofukushi/kosodate/azukari/shien/help.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:miyagi-sendai-prenatal-postpartum-helper:bWl5YWdpLXNlbmRhaS1wcmVuYXRhbC1wb3N0cGFydHVtLWhlbHBlcnxwRGxNSWpxWGwzYmlGQk9wUFkya2RSTWI=' from public.support_programs sp where sp.slug='miyagi-sendai-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'okayama' and m.slug = 'okayama'), 'okayama-okayama-prenatal-postpartum-helper', 'シルバー世代産前産後応援事業', '岡山市が実施するシルバー世代産前産後応援事業です。家事・育児の援助を必要とする産前・産後の世帯を対象に、岡山市シルバー人材センターに登録する60歳以上の支援者が家庭を訪問し、家事支援（食事の準備や片付け、洗濯、掃除、買い物）と育児支援（授乳の手伝い、おむつ交換、沐浴介助）を行う事業です。1回2時間まで（1日2回まで利用可能）、出産予定日の1か月前から出産日の5か月後まで（多胎児・多子世帯は12か月後まで）の期間内に合計30回まで（多胎児・多子世帯は65回まで）利用できるとされています。岡山市が別に実施する産後ケア事業（助産師等による母子の心身のケア、宿泊型・通所型・訪問型）や、ファミリー・サポート・センター（会員同士の相互援助を市がマッチングする事業）とは別の事業です。所得制限の有無やキャンセル規定など、公式ページに明記されていない項目もあるため、利用を検討する場合は必ず岡山市へご確認ください。', '出産の前後で家事や育児の手伝いが必要な岡山市在住の妊産婦さんに、60歳以上の支援員さんが家に来て、掃除や洗濯、食事の準備、赤ちゃんのお世話などを手伝ってくれる制度です。1時間550円で利用できます。', 'service', '岡山市内在住で、出産予定日の1か月前から出産日の5か月後まで（多胎児や5歳以下の子どもが3人以上いる多子世帯の場合は出産日の12か月後まで）の妊産婦で、家事・育児の援助を必要とする方が対象となる可能性があります。所得制限の有無など詳細な条件は公式ページに明記されていないため、岡山市へご確認ください。', '利用料金は1時間当たり550円（1か月分をまとめて支払い）。1回2時間まで、1日2回まで利用可能で、期間内に合計30回まで（多胎児・多子世帯は65回まで）利用できるとされています。', '明確な申請期限の記載は確認できませんでした。公式ページには「できるだけ早めにご依頼ください」と案内されています。具体的な利用開始までの必要日数は岡山市へご確認ください。', '次の3つの方法で申請できます。(1) パソコンまたはスマートフォンから岡山市電子申請サービスにアクセスして申し込む、(2) 必要事項を記入した利用申請書を地域子育て支援課へ郵送する、(3) 岡山市役所9階の地域子育て支援課窓口で申請する。申請後、支援内容や日時については岡山市シルバー人材センターへ相談・依頼する流れとされています。', '親子手帳（分娩予定日欄へ記入後のページ）が必要です。多胎児・多子世帯の場合は、子どものマイナンバーカードまたは健康保険資格確認書のデータも必要とされています。', TRUE, '岡山っ子育成局子育て支援部地域子育て支援課（利用申請）／岡山市シルバー人材センター（支援内容・日程の相談）', '086-803-1224', NULL, 'https://www.city.okayama.jp/kurashi/0000013001.html', 'シルバー世代産前産後応援事業 | 岡山市', '2026-07-01', 'high', ARRAY['applicationDeadlineText', '所得制限の有無', '区外在住者・里帰り出産時の扱い', 'キャンセル規定']::text[], '対象条件・利用できる時間・利用料は世帯状況や岡山市の認定により異なる場合があります。本ページは概要であり、最新かつ正確な情報は必ず岡山市の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
