insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"okayama-okayama-prenatal-postpartum-helper","status":"published","title":"シルバー世代産前産後応援事業","officialUrl":"https://www.city.okayama.jp/kurashi/0000013001.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:okayama-okayama-prenatal-postpartum-helper:b2theWFtYS1va2F5YW1hLXByZW5hdGFsLXBvc3RwYXJ0dW0taGVscGVyfEkrTWJoV3ppRE1qUWZZemo0S25vMXNJNA==' from public.support_programs sp where sp.slug='okayama-okayama-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'osaka'), 'osaka-osaka-prenatal-postpartum-helper', '大阪市子育て応援ヘルパー派遣事業', '大阪市が実施する子育て応援ヘルパー派遣事業です。市内在住で0〜2歳児を養育する家庭（妊娠中の場合は出産予定日の2か月前から登録可能）を対象に、委託を受けた訪問支援事業者のヘルパーが自宅を訪問し、家事支援（食事の準備・後片付け、洗濯、掃除・整理整頓、生活必需品の買い物等）と育児支援（授乳・離乳食の介助、おむつ交換、沐浴介助、きょうだいの保育所等への送迎支援等）を行います。こどもの預かりやベビーシッターは行わず、利用時には保護者と対象児童の在宅が必要とされています。利用時間数は0歳児は合計40時間、1歳児・2歳児はそれぞれ合計20時間までとされており、対象年齢や利用時間の上限を超える利用はできません。なお、大阪市が別に実施する産後ケア事業（母子の心身のケアを行う宿泊型・通所型・訪問型の事業で、公式ページに「託児、保育、家事のサービスではありません」と明記）とは異なる事業であり、また支援の必要性を行政が個別に判断するハイリスク家庭向けの養育支援訪問事業とも異なる、全対象家庭向けの家事・育児支援サービスです。対象要件や利用可能時間の詳細は世帯の状況により異なる可能性があるため、利用前に大阪市子育て応援ヘルパー事務局または大阪市の公式サイトで確認することが推奨されます。', '大阪市内に住む0歳から2歳のこどもを育てている家庭（妊娠中の人も出産予定日の2か月前から登録可）で、ヘルパーが家に来て、家事（掃除・洗濯・食事の準備など）や育児（おむつ替え・沐浴の手伝いなど）を手伝ってくれる制度です。利用したいときは専用サイトで登録し、予約してから利用します。', 'service', '大阪市内に住み、0歳から2歳児（2歳児は2歳及び3歳の誕生日を迎えてから最初の3月31日まで）を養育しているすべての家庭が対象となる可能性があります。妊娠中の場合は出産予定日の2か月前から利用登録ができるとされています。利用時には保護者と対象児童が在宅している必要があるとされています。所得制限等の受給要件は公式資料上見当たりませんが、利用料の減免については生活保護世帯・市民税非課税世帯に限られるとされています。', '利用料は1時間あたり1,500円とされています（生活保護世帯・市民税非課税世帯は所定の書類提出による減免申請で無料になる可能性があります）。利用時間数の上限は、0歳児は合計40時間、1歳児は合計20時間、2歳児は合計20時間までとされています（対象児童が複数いる家庭はそれぞれの利用時間数の合計）。利用可能日時は月曜〜日曜の8時〜20時（年末年始12/29〜1/3を除く）で、1日1回・1回2時間/3時間/4時間のいずれかとされています。利用日前営業日17時以降のキャンセルは1,500円のキャンセル料が発生する可能性があるとされています。', 'マイページでの利用予約は利用日の2か月前から10営業日前まで可能とされ、9営業日前からは電話のみでの予約受付、2営業日前以降は予約不可とされています。早めの予約申請が推奨されています。利用登録自体にはこの予約期限とは別に随時申請できるとみられますが、詳細は公式サイトで確認してください。', '大阪市公式サイトから事業専用ホームページ（子育て応援ヘルパーホームページ）にアクセスし、（1）利用登録申請、（2）利用予約申請、（3）利用、の順に進めるとされています。申請承認後にマイページが作成され、以降の予約や減免申請もマイページから行うとされています。インターネットでの申請ができない場合は大阪市子育て応援ヘルパー事務局への問い合わせが案内されています。', '通常の利用登録に必要な書類は公式資料上明記が確認できませんでした。利用料等の減免を申請する場合は、市民税非課税世帯は世帯員のうち収入のある方全員分の市民税課税（所得）証明書、生活保護世帯は世帯全員の氏名・生年月日が記載された生活保護適用証明書（または休日・夜間等診療依頼証）が必要とされています。詳細は公式の「利用のしおり」またはこども青少年局子育て支援部管理課で確認してください。', TRUE, '大阪市子育て応援ヘルパー事務局（大阪市担当：こども青少年局子育て支援部管理課児童支援対策グループ）', '06-6476-8061', 'https://ouenhelper-osaka.com/', 'https://www.city.osaka.lg.jp/kodomo/page/0000638446.html', '大阪市：大阪市子育て応援ヘルパー（子育て・教育に関すること>子育てに関すること）', '2026-07-01', 'high', ARRAY['targetPeople（所得制限の有無の明記は確認できず、減免対象要件からの推定を含む）', 'requiredDocumentsText（通常利用登録時の必要書類の明記は確認できず）', 'applicationDeadlineText（利用登録自体の申請期限の明記は確認できず、予約期限のみ確認）', 'ファミリーサポートセンターとの制度上の重複・すみ分けについての公式な明記文は確認できていない（事業設計上の違いからの推定）']::text[], '対象条件・利用できる時間・利用料の減免要件は世帯状況や大阪市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず大阪市の公式サイトおよび大阪市子育て応援ヘルパー事務局でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
