insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"osaka-osaka-prenatal-postpartum-helper","status":"published","title":"大阪市子育て応援ヘルパー派遣事業","officialUrl":"https://www.city.osaka.lg.jp/kodomo/page/0000638446.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:osaka-osaka-prenatal-postpartum-helper:b3Nha2Etb3Nha2EtcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8RE42M2JyK09rQzFRTWJsc3dpcUNCUi9k' from public.support_programs sp where sp.slug='osaka-osaka-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'sakai'), 'osaka-sakai-prenatal-postpartum-helper', '堺市育児支援ヘルパー派遣', '堺市が実施する育児支援ヘルパー派遣事業です。妊娠中や出産後の心身の負担により家事や育児が困難であるにもかかわらず、家族や親族などお手伝いをしてくれる人がいない家庭に対し、ヘルパーが自宅を訪問して家事支援（食事の準備・後片付け、洗濯、居室の掃除、買い物など）と育児支援（授乳の手伝い、おむつ交換、沐浴介助など）を行います。対象は妊娠届出日から出産後1年以内の方とされ、里帰り出産期間中は対象外とされています。利用回数は50回以内（多胎出産の場合は80回以内）、1回1時間以上2時間以内、1日2回まで利用できる可能性があると公式に記載されています。利用料金は世帯の課税状況等により異なります。堺市が別に実施する産後ケア事業（助産師等による母子の心身のケアで、家事援助は行わないと明記）や、堺市子育て世帯家事・育児訪問支援事業（対象は18歳までの子どもがいてヤングケアラー状態にある家庭で、産前産後を対象とするものではない）とは異なる事業です。対象条件・利用可能回数・利用料は世帯状況や市の認定により異なるため、利用前に堺市へ確認してください。', '妊娠中や産後で、家事や赤ちゃんのお世話を手伝ってくれる人が身近にいないとき、堺市のヘルパーが家に来て家事や育児を手伝ってくれる制度です。利用したいときは早めに区役所の窓口に申し込みます。', 'service', '堺市の住民基本台帳に登録されている方で、妊娠届出日から出産後1年以内の間にあり、出産前後の心身の負担により家事や育児を行うことが困難であるにもかかわらず、家族や親族等の手伝ってくれる人がいない家庭が対象となる可能性があります。里帰り出産期間中は対象外とされています。詳しい要件は区役所子育て支援課で確認してください。', '利用回数は1年度あたり50回以内（多胎出産の場合は80回以内）、1回につき1時間以上2時間以内、1日2回まで利用できる可能性があります。利用料金は世帯の課税状況等の区分により異なり（生活保護世帯等は無料、その他の世帯は1時間あたり0〜700円程度、1〜2時間で0〜1,400円程度の範囲とされています）、詳細は区役所子育て支援課で確認してください。', '利用開始希望日の10日前までに申請するとされています。', '「堺市育児支援ヘルパー派遣申請書」に記入し、居住する区の区役所子育て支援課窓口への持参、郵送、または堺市電子申請システムから申し込むことができるとされています。', '堺市育児支援ヘルパー派遣申請書のほか、生活保護受給世帯等に該当する場合は生活保護受給証明書等の提出が必要とされる場合があります。市民税非課税世帯等で転居等により所得情報が確認できない場合は、前住所地での課税証明書等の提出を求められることがあります。詳細は区役所子育て支援課で確認してください。', TRUE, '堺市 こども育成課（または居住区の区役所子育て支援課）', '072-228-7612', 'https://lgpos.task-asp.net/cu/271403/ea/residents/portal/home', 'https://www.city.sakai.lg.jp/kosodate/hughug/ninshin_shusan/umaretara/ikujihelper10.html', '堺市育児支援ヘルパー派遣　堺市', '2026-07-01', 'high', ARRAY['benefitAmountText（世帯区分ごとの詳細な料金表は要綱別表に依拠しており、案内ページでは概要のみ確認）', 'requiredDocumentsText（必要書類の全リストは申請書様式側にある可能性があり、案内ページ・要綱からの間接確認）']::text[], '対象条件・利用できる回数や時間・利用料は世帯状況や市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ず堺市の公式サイトおよびお住まいの区役所子育て支援課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
