insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'saitama' and m.slug = 'saitama'), 'saitama-saitama-prenatal-postpartum-helper', '子育てヘルパー派遣事業', 'さいたま市が実施する子育てヘルパー派遣事業です。妊娠中の方、1歳未満の乳児を養育する保護者、流産・死産から1年以内で体調不良の方、1歳から小学6年生までの児童を養育していて体調不良の保護者を対象に、子育てヘルパーが家庭を訪問して家事援助（食事の準備・後片付け、衣類の洗濯・補修、掃除・整理整頓、生活必需品の買い物）や育児援助（授乳、おむつ交換、沐浴などのお手伝い・補助、適切な育児環境の整備）を行うとされています。公式ページには、ヘルパーが単独で乳幼児を預かることはできないと明記されています。利用できる日数は、妊娠中は1歳の誕生日前日まで10日、産後は20日（多胎児・多子の場合は30日）、流産・死産の場合は1年間で10日などとなる可能性があり、1日2回まで利用できるとされています。市が別に実施する産後ケア事業（助産師等による母子の心身のケア、訪問型・デイサービス型・宿泊型）や、さいたまファミリー・サポート・センター（会員同士の相互援助）とは異なる事業として、公式サイト上でも別項目として案内されています。対象や利用できる日数・料金は世帯状況等により異なるため、利用前にさいたま市へ確認してください。', '妊娠中や産後、子育て中に家事や育児を手伝ってくれる人が身近にいないとき、さいたま市の子育てヘルパーが家に来て、家事や育児のお手伝いをしてくれる制度です。利用したいときは、早めに事業所へ申し込みます。', 'service', 'さいたま市に住民登録があり、次のいずれかに該当する方が対象となる可能性があります。妊娠中の方、1歳未満の乳児を養育している保護者、流産または死産から1年以内で体調不良の方、1歳から小学6年生までの児童を養育していて体調不良の保護者。DV等で他自治体へ避難している方は対象外とされています。', '利用料金は世帯の所得状況等により異なります。生活保護受給世帯・中国残留邦人等支援給付受給世帯は無料、市町村民税非課税世帯・ひとり親家庭等医療費受給世帯は1時間あたり250円、その他の世帯は1時間あたり500円とされています。交通費や購入した品物代等の実費は別途負担となる場合があります。利用できる日数は、妊娠中は10日（産前）、産後は20日（多胎児・多子は30日）、流産・死産は1年間で10日、体調不良児童の養育は決定日から1年間で10日とされ、1日2回まで利用できる可能性があります。', '産前産後の利用で利用時期があらかじめ決まっている場合は、おおむね1か月前を目安に申し込むよう案内されています。詳しい日程は事業所や窓口に確認してください。', '利用を希望する事業所へ直接電話で申し込みます。電話受付時間外の場合は、メールまたはFAXでの申込みも可能とされ、その際は件名を「さいたま市子育てヘルパー派遣利用希望」とし、氏名・住所・連絡先・利用開始希望時期を記載する必要があるとされています。申込み後、事前訪問等を経て申請書を記入する流れとなる可能性があります。', '公式ページには申請書（事前訪問後に記入）についての記載があります。具体的な必要書類の一覧は明記されていないため、申込み先の事業所またはさいたま市子育て支援課に確認してください。', FALSE, 'さいたま市 子ども未来局 子ども育成部 子育て支援課 支援係', '048-829-1271', NULL, 'https://www.city.saitama.lg.jp/003/001/011/p091869.html', '子育てヘルパー派遣事業 - さいたま市', '2026-07-01', 'high', ARRAY['requiredDocumentsText（申請書以外の必要書類の詳細は公式ページに明記なし）', 'officialSourceTitle（HTML titleタグを直接確認できず、パンくずリストと見出しから復元）', 'applicationDeadlineText（申込期限は『産前産後の場合はおおむね1か月前』とのみ記載され、流産・死産や児童養育ケースの期限は明記なし）']::text[], '対象条件・利用できる日数・利用料は世帯状況や市の認定により異なります。本ページは概要であり、最新かつ正確な情報は必ずさいたま市の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
