insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"saitama-saitama-prenatal-postpartum-helper","status":"published","title":"子育てヘルパー派遣事業","officialUrl":"https://www.city.saitama.lg.jp/003/001/011/p091869.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:saitama-saitama-prenatal-postpartum-helper:c2FpdGFtYS1zYWl0YW1hLXByZW5hdGFsLXBvc3RwYXJ0dW0taGVscGVyfDNqQmw4TGIzOXlVd0lRTFN4cUptOEFMWg==' from public.support_programs sp where sp.slug='saitama-saitama-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'hamamatsu'), 'shizuoka-hamamatsu-prenatal-postpartum-helper', 'はますくヘルパー利用事業（産前・産後ヘルパー）', '浜松市が実施するはますくヘルパー利用事業です。妊娠中（親子健康手帳交付後）または3歳未満の子どもを養育している保護者を対象に、ヘルパーが家庭を訪問し、家事の手伝いや育児相談を行います。利用にかかる費用の一部が浜松市から助成される仕組みで、市の広報紙でも「産前・産後ヘルパー」として案内されています。利用時間は妊娠中から子どもが3歳の誕生日を迎える前日までの間で計75時間以内（中山間地域は150時間以内、未熟児や障がい児の場合は加算がある可能性）とされ、1日2回・1回1時間単位で最大4時間まで、利用時間帯は午前7時から午後7時までとされています。助産師等による産後ケア事業とは別の、家事・育児支援のヘルパー派遣事業です。対象や利用時間・料金は世帯状況や登録内容により異なるため、利用前に浜松市へ確認してください。', '妊娠中や3歳未満の子どもを育てているとき、家に来て家事を手伝ったり育児の相談にのってくれたりするヘルパーを頼める制度です。費用の一部を浜松市が負担してくれます。利用したいときは事前に申請します。', 'service', '浜松市民で、妊娠中（親子健康手帳交付後）または3歳未満の子どもを養育している保護者が対象となる可能性があります。', '妊娠中から子どもが3歳の誕生日を迎える前日までの間で、合計75時間以内（中山間地域に居住する場合は150時間以内）利用できる可能性があるとされています。1日2回まで、1回1時間単位で最大4時間まで、利用時間帯は午前7時から午後7時までとされています。公費負担額は1時間あたり1,500円（市民税非課税世帯・生活保護世帯は1,800円）が基本とされ、利用者はヘルパー事業者の設定料金との差額を負担するとされています。交通費は1kmにつき40円を上限に公費負担される可能性があります。', '利用前に事前の登録・申請が必要とされていますが、申請から利用開始までの具体的な必要日数の記載は確認できませんでした。', '窓口での手続きまたはオンライン申請に対応しているとされています。利用者登録後、受託事業者一覧から事業者を選び、直接予約する流れとされています。', '親子健康手帳の写し。未熟児の場合は養育医療券、障がい児の場合は各種障害者手帳のコピーなどが必要とされる可能性があります。', TRUE, '浜松市 子育て支援課', '053-457-2792', NULL, 'https://www.hamamatsu-pippi.net/contents/7913.html', 'はますくヘルパー利用事業 - 浜松市子育て情報サイト ぴっぴ', '2026-07-01', 'medium', ARRAY['officialUrl（浜松市公式ドメイン直下の制度詳細ページが見当たらず、市公式の子育て情報サイト『ぴっぴ』を情報源としている）', 'contactPhone（複数の番号表記が見つかっており、どちらが正確か要確認）', 'applicationDeadlineText（申請から利用開始までの必要日数が不明）']::text[], '対象条件・利用できる時間・利用料・助成額は世帯状況や選ぶヘルパー事業者により異なります。本ページは概要であり、最新かつ正確な情報は必ず浜松市の公式サイトおよび窓口（子育て支援課）でご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'shizuoka-hamamatsu-prenatal-postpartum-helper' and c.slug = 'birth' on conflict do nothing;
