insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"shizuoka-hamamatsu-prenatal-postpartum-helper","status":"review","title":"はますくヘルパー利用事業（産前・産後ヘルパー）","officialUrl":"https://www.hamamatsu-pippi.net/contents/7913.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:shizuoka-hamamatsu-prenatal-postpartum-helper:c2hpenVva2EtaGFtYW1hdHN1LXByZW5hdGFsLXBvc3RwYXJ0dW0taGVscGVyfGJ2a2pYU1Z6UjZXWm8xenVEeXQrS0FDaA==' from public.support_programs sp where sp.slug='shizuoka-hamamatsu-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'shizuoka'), 'shizuoka-shizuoka-prenatal-postpartum-helper', '子育て支援ヘルパー派遣事業', '静岡市が実施する子育て支援ヘルパー派遣事業です。静岡市と契約を結んだ事業者がヘルパーを派遣し、妊娠中や子育て中で家族などのサポートが得られず、日中一人で家事・育児を行わなければならない家庭を対象に、食事の準備・後片付け、衣類の洗濯や補修、居室等の掃除・整頓、生活必需品の買い物、関係機関との連絡調整などを支援します。対象は「妊婦・乳児（生後1歳未満）のいる世帯」と「1歳以上3歳未満の幼児を2人以上養育する多子世帯」に分かれ、利用できる時間の上限や対象期間が区分により異なるとされています。母子健康手帳の交付後から利用者登録ができます。助産師等による産後ケア事業とは別の家事・育児支援の事業です。対象や利用時間・料金は世帯状況や登録区分により異なるため、利用前に静岡市へ確認してください。', '妊娠中や小さな子どもを育てているときに、家事や育児を手伝ってくれる家族が身近にいない場合、静岡市と契約したヘルパーが家に来て食事の準備や掃除、洗濯などを手伝ってくれる制度です。利用するには前もって登録が必要です。', 'service', '静岡市に住んでおり、日中に家事や育児を手伝う家族などがいない家庭が対象となる可能性があります。妊娠中または生後1歳未満の乳児を養育する世帯（黄色の登録証）と、1歳以上3歳未満の幼児を2人以上養育する多子世帯（水色の登録証）に区分されているとされています。', '妊婦・乳児世帯は満1歳の誕生日前日まで最大100時間、多子世帯は満3歳の誕生日前日まで年間60時間まで利用できる可能性があるとされています。利用者負担金は1時間あたり900円が基本ですが、市民税非課税世帯（ひとり親世帯を除く）は450円、生活保護世帯・ひとり親世帯で市民税非課税の世帯は無料になる可能性があるとされています。別途ヘルパーの交通費がかかる場合があります。利用可能な時間帯は8時から18時までとされています。', '利用前に利用者登録が必要とされていますが、申請から利用開始までの具体的な必要日数の記載は公式ページで確認できませんでした。', '各区役所子育て支援課へ利用者登録申請書類を提出するか、電子申請での登録に対応しているとされています。登録後、希望する事業者へ直接予約する流れとされています。', '子育て支援ヘルパー派遣事業利用者登録申請書、母子健康手帳表紙の写し（妊娠中の場合）。減免を希望する場合は生活保護受給証明書または市民税非課税証明書等が必要とされる可能性があります。', TRUE, '葵福祉事務所子育て支援課・駿河福祉事務所子育て支援課・清水福祉事務所子育て支援課', '054-221-1096（葵区）', NULL, 'https://www.city.shizuoka.lg.jp/s2873/s001935.html', '子育て支援ヘルパー派遣事業：静岡市公式ホームページ', '2026-07-01', 'high', ARRAY['applicationDeadlineText（登録から利用開始までの必要日数が不明）', 'benefitAmountText（減免区分ごとの正確な適用条件は要確認）']::text[], '対象条件・利用できる時間・利用料は世帯の登録区分（妊婦・乳児世帯／多子世帯）や所得状況により異なります。本ページは概要であり、最新かつ正確な情報は必ず静岡市の公式サイトおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
