insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei prenatal-postpartum-helper import', '{"slug":"shizuoka-shizuoka-prenatal-postpartum-helper","status":"published","title":"子育て支援ヘルパー派遣事業","officialUrl":"https://www.city.shizuoka.lg.jp/s2873/s001935.html","topic":"prenatal-postpartum-helper"}'::jsonb, 'seirei:shizuoka-shizuoka-prenatal-postpartum-helper:c2hpenVva2Etc2hpenVva2EtcHJlbmF0YWwtcG9zdHBhcnR1bS1oZWxwZXJ8dDRJTFRtMkI1UFNEQlJ0Y1BTLzlyZWZZ' from public.support_programs sp where sp.slug='shizuoka-shizuoka-prenatal-postpartum-helper' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.nagoya.jp/kodomoseishonen/page/0000096194.html', 'WebSearchで「名古屋市 産前産後ヘルパー」「名古屋市 育児支援ヘルパー派遣」を検索し、名古屋市公式サイト内の「産前・産後ヘルプ事業」ページを複数発見。2つの独立URL（同一事業の別カテゴリ掲載）をWebFetchで実際に取得し、対象者・利用期間・時間上限・料金区分・申請窓口・必要書類・担当部署の電話番号までを確認。ページには「令和7年10月1日以降のご利用分」から利用期間が拡充される記載があり、現在日付（2026年7月）は施行後にあたるため新基準を採用。ページ本文に「ファミリー・サポート・センター」「産後ケア事業」とは別事業である旨の明記があり、ヘルパー単独で赤ちゃんを預かることはできない点も含め、家事代行・育児支援員派遣の事業であることを確認、産後ケア事業（助産師による母子ケア）およびファミリーサポートセンター（会員間相互援助）との混同がないことを確認済み。オンライン申請の可否は明示的な記載がなく、申込期限の「原則」表現も含め不確実性が残るためuncertainFieldsに計上した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='aichi' and m.slug='nagoya' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.chiba.jp/kodomomirai/yojikyoiku/shien/engel2.html', '「千葉市 産前産後ヘルパー」「千葉市 育児支援訪問事業」等で検索。千葉市子育てナビ経由で「エンゼルヘルパー」（家事・育児支援ヘルパー派遣）を特定し、公式ページと初回利用ガイド・FAQをWebFetchで実際に取得し、対象要件・支援内容・料金・上限回数・申請方法・問い合わせ先を確認した。ページ本文に「助産師による心身のケアは別事業」との記載があり、産後ケア事業との混同がないことを公式に確認。ファミリーサポートセンター（市はマッチングのみ）への言及・混同はなし。統括者が officialUrl にWebFetchで再アクセスし、ページタイトル・対象者・利用料金・利用回数の記載を実機で再確認し、内容の一致を検証済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.fukuoka.lg.jp/kodomo-mirai/k-sukoyaka/child/sangohelper.html', '検索を実施し、公式サイト内の「福岡市産前・産後ヘルパー派遣事業のご案内」ページを特定。WebFetchで2回取得し、事業概要・対象要件・利用回数と時間の上限・料金・様式・問い合わせ先を確認した。申請の具体的な提出手順とオンライン申請の可否は公式ページに明記がなかったためuncertainFieldsに含めた。福岡市が別に実施する「産後ケア事業」は別ページ・別事業として明確に区別されていることを確認済みで、混同していない。ファミリー・サポート・センターも別物として除外した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='fukuoka' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kitakyushu.lg.jp/contents/11700376.html', '検索を実施し、公式サイト内の「産前産後子育て支援ヘルパー派遣事業のご案内」を発見。WebFetchで本文を2回取得し、目的・対象・利用回数・利用料・申込方法・問い合わせ先を確認した。「産後ケア事業」は助産師等による母子の心身ケアであり、家事・育児支援ヘルパー派遣とは明確に異なる別事業であることを確認した。また類似の「子育て世帯訪問支援事業」もWebFetchで確認したが、要支援認定世帯向けの見守り・虐待予防色が強い別制度と判断し、ユーザー定義に最も一致する『産前産後子育て支援ヘルパー派遣事業』を主制度として採用した。ファミリーサポートセンターは今回の検索結果には明確に出現せず、混同は生じていない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='kitakyushu' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hiroshima.lg.jp/living/kosodate/1021253/1025913/1038835.html', 'WebSearchで複数語を検索し、公式ドメイン内の候補URLを複数特定した。WebFetchで実際にページ本文を取得し、(1)「広島市産後ヘルパー派遣事業」が家事・育児支援ヘルパーの直接派遣事業であること、(2)「広島市産後ケア事業（宿泊型・通所型・訪問型）」が助産師による母子の医療的ケア中心の別事業であり、両ページ間で相互リンクされ明確に区別されていること、(3)ファミリー・サポート・センターは会員同士の相互援助でマッチング支援のみであり対象外であることを確認した。事業名は「産後」のみで「産前」を含まないが、これは広島市の正式名称どおりであり、申請開始は妊娠8か月からと明記されている点を本文に反映した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://kosodate.city.sapporo.jp/nenrei/ninshin_shussan/index.html', '「札幌市 産前産後ヘルパー 育児支援訪問事業」「札幌市 産前産後家庭訪問支援事業」「札幌市 養育支援訪問事業」「札幌市 産前産後 ヘルパー派遣 家事援助」「札幌市 産前産後子育てヘルプ事業」「札幌市 育児支援ヘルパー派遣事業 対象 利用料」等、複数系統のキーワードでWebSearchを実施した。札幌市子育てサイト（kosodate.city.sapporo.jp）の「妊娠～出産」目次ページ、および「札幌市産後ケア事業」ページをWebFetchで実際に取得して内容を確認したが、家事（掃除・洗濯・食事準備）や育児（授乳・沐浴・おむつ替え等）を代行するヘルパーを家庭に派遣する独立事業は、確認できる範囲では見当たらなかった。見つかったのは(1)札幌市産後ケア事業（助産師等によるケアで医療・保健寄り、対象外として除外）、(2)乳児家庭全戸訪問・養育支援訪問事業（保健師等による相談・情報提供が中心でヘルパー派遣ではない）、(3)さっぽろ子育てサポートセンター（ファミリー・サポート・センター事業＝会員間相互援助、対象外として除外）の3つで、いずれも今回の定義（家事・育児支援ヘルパー派遣）には該当しないため、産後ケア事業・ファミリーサポートセンターと混同しないよう区別した上でnot_found_on_official_siteと判定した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hokkaido' and m.slug='sapporo' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kobe.lg.jp/a86732/kosodate/maternity/consult/sanzensango/index.html', '「神戸市 産前産後ヘルパー派遣」「神戸市 育児支援訪問事業」「神戸市 産前産後ホームヘルプサービス 家事 育児 内容」「神戸市 産前産後ホームヘルプサービス 問い合わせ 電話」を検索し、神戸市公式サイト内の複数ページをWebFetchで実際に取得して確認した。主ページで対象・料金・回数・申請方法を確認し、連絡先一覧ページと総合案内ページ、契約事業者一覧ページも確認して、実施主体が市の委託事業者であること、および同市が別途持つ「産後ケア事業（宿泊・通所・訪問型、助産師によるケア）」「多胎児家庭ホームヘルプサービス」とはリンク一覧上も別項目として明確に区別されていることを確認した。ファミリーサポートセンターへの言及は検索結果に出現せず、混同の懸念はない。電話番号は個別記載がなく区役所代表番号経由のため空欄とした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kawasaki.jp/450/page/0000030633.html', '「川崎市 産前産後ヘルパー 派遣」「川崎市 育児支援 訪問 家事支援」で検索し、公式サイト内の事業ページと関連FAQページを発見。両方をWebFetchで実際に取得し、事業名・対象・利用時間・料金・申請方法・問い合わせ先を確認した。事業内容が助産師によるケアではなく家事・育児ヘルパー派遣であることを確認し、川崎市の別事業である産後ケア事業やふれあい子育てサポート事業（ファミリー・サポート・センター、会員間相互援助）とは異なる、市認定事業者によるヘルパー派遣事業であることを確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='kawasaki' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sagamihara.kanagawa.jp/kosodate/1026602/kosodate/1025906.html', '「相模原市 産前産後ヘルパー 派遣」「相模原市 育児支援家庭訪問事業」等で検索したところ、相模原市の「産後ケア事業」（助産師によるケア）とは別に、「子育て世帯訪問支援事業」という家事支援ヘルパー派遣事業を発見し、WebFetchで2回取得した。対象は出生後1年以内の乳児・多胎児世帯とヤングケアラー世帯の複合事業であり、「産前」を含む純粋な産前産後ヘルパー事業とは名称・対象範囲がやや異なる点を確認した。産後ケア事業およびファミリー・サポート・センターとは明確に別の、市委託の家事支援事業者による訪問型ヘルパー派遣であることを確認済み。対象範囲の特殊性（産前非対象、ヤングケアラーと共有の枠組み）のためpublishStatusはreviewとした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='sagamihara' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.yokohama.lg.jp/kosodate-kyoiku/oyakokenko/ninshin/sanzensango.html', '「横浜市 産前産後ヘルパー派遣事業」「横浜市 育児支援訪問事業」等複数語でWebSearchし、公式サイト内ページを特定。WebFetchで本文を実際に取得し、正式名称・対象者・支援内容・利用料金（1回1,500円、産前産後各20回以内）・申請窓口（各区こども家庭支援課）・申請期限（7日前まで）・問い合わせ先・最終更新日を確認した。同ページの関連リンクに「横浜市産後母子ケア事業」（助産師による訪問型・宿泊型ケア）が別事業として並記されており、支援内容が明確に異なることから、産後ケア事業とは混同していないことを確認した。ファミリーサポートセンター（横浜子育てサポートシステム）は本ページ内に言及がなく、別の会員間相互援助制度であるため対象外として除外した。統括者が officialUrl に再度WebFetchでアクセスし内容の一致を検証済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='yokohama' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kumamoto.jp/kiji003517/index.html', '検索を実施した結果、熊本市公式サイト内の「産前産後ホームヘルプサービス事業について」ページがヒットし、WebFetchで本文全体（対象者要件、利用料金600円/時間・40回上限、区ごとの申請窓口5区分の電話番号）を実際に取得・確認した。同ページには「産後ケア」という語は一切登場せず、別途「熊本市産後ケア事業について」（助産師等による母子の心身ケア）という独立ページが公式サイトに存在することを確認したため、両事業が熊本市において明確に別制度として運用されていることを確認した上で、今回は家事・育児支援ヘルパー派遣のみを対象として記載した。ファミリーサポートセンターとの違いも区別できている。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kumamoto' and m.slug='kumamoto' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kyoto.lg.jp/hagukumi/page/0000206563.html', '複数系統で検索した結果、京都市には家事・育児支援ヘルパー派遣事業が2種類あることを確認した：(1)対象を第三子以降・多胎児に限定する「産前産後ヘルパー派遣事業」（WebFetch実施）と、(2)産後うつ等の要支援家庭を対象とする「育児支援ヘルパー派遣事業」（実施要領・市共通ページ・区案内、いずれもWebFetch実施）。今回は「産前産後」を正式名称に含み、料金・回数・申請窓口・必要書類・オンライン申請可否まで最も具体的に確認できた前者を主制度として採用した。産後ケア事業（スマイルママ・ホッと事業）はWebFetchで内容を確認し、助産師による母子ケアでありヘルパー派遣とは別物と確認した。ファミリーサポートセンターへの言及は確認した公式ページ内に見当たらず、混同はしていない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kyoto' and m.slug='kyoto' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sendai.jp/kodomo-chiiki/kurashi/kenkotofukushi/kosodate/azukari/shien/help.html', '「仙台市 産前産後ヘルパー」「仙台市 育児支援訪問事業」「仙台市 産前産後家庭訪問支援事業」「仙台市 養育支援訪問事業」「仙台市 産後家庭ヘルプサービス」の5系統でWebSearchを実施。仙台市公式サイト(city.sendai.jp)の「産前・産後のサポート」一覧ページと「子育て世帯訪問支援事業（育児ヘルパー派遣）」ページの2つをWebFetchで実際に取得し内容を確認した。仙台市公式サイトには「産後ケア事業」（助産師による訪問・宿泊・デイサービス型ケア）が別ページとして並列掲載されており、これは医療・保健寄りの別事業として明確に区別し、今回の対象からは除外した。ファミリーサポートセンターに関する記載は今回のページ内には見当たらず、混同は生じていない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='miyagi' and m.slug='sendai' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-07-01', 'https://www.city.niigata.lg.jp/kosodate/ninshin/index.html', '「新潟市 産前産後ヘルパー 派遣事業」「新潟市 育児支援家庭訪問事業」「新潟市 養育支援訪問事業」「新潟市 産前・産後サポート事業 家事支援」「新潟市 多胎妊産婦 サポーター等派遣事業」「新潟市 家事育児サポーター 派遣事業」等、10通り以上の検索語で調査した。新潟市公式サイトの「妊娠・出産・子育て」トップページおよび「子育て支援」一覧ページをWebFetchで取得したが、家事・育児ヘルパーを家庭に派遣する事業へのリンクは見当たらなかった。見つかったのは（1）新潟市産後ケア事業（助産師等による宿泊・デイケア・訪問ケア、心身のケアや育児指導が中心で家事代行は含まない）と（2）新潟市ファミリー・サポート・センター（新潟市社会福祉協議会が委託運営、依頼会員と提供会員による有償ボランティア型の相互援助で、市はマッチング支援のみ）の2つのみで、いずれも指示された対象事業とは異なることをファミサポの公式ページで運営構造まで確認した。新潟市が直接実施または委託する『家事・育児支援ヘルパー派遣』の独立事業は、確認日時点で公式サイト上に発見できなかったため、not_found_on_official_siteと判定した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='niigata' and m.slug='niigata' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.okayama.jp/kurashi/0000013001.html', '「岡山市 産前産後ヘルパー」「岡山市 育児支援訪問事業」「岡山市 産前産後家庭訪問支援事業」「岡山市 養育支援訪問事業」の4系統でWebSearchを実施した結果、岡山市公式サイト内で家事・育児支援ヘルパー派遣に該当する事業は「シルバー世代産前産後応援事業」のみであることを確認した。同ページをWebFetchで2回取得し、事業内容・対象・料金・申請方法・問い合わせ先を確認した。区別確認のため、産後ケア事業ページもWebFetchで取得し、助産師による心身ケア中心の別事業であり、ページ内で別項目として区別されていることを確認した。また「養育支援訪問事業」は児童虐待予防を目的とした保健・福祉専門職による家庭訪問事業であり、対象・性質が異なる別制度と判断し除外した。ファミリー・サポート・センターとも明確に別制度であることを確認し、混同していない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='okayama' and m.slug='okayama' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.osaka.lg.jp/kodomo/page/0000638446.html', '複数系統で検索し、大阪市公式サイト内の「大阪市子育て応援ヘルパー」ページを発見。WebFetchで同ページと専用サイト、および公式PDF「利用のしおり」を取得し、事業概要・対象・料金・時間数上限・申請フローを確認した。産後ケア事業ページもWebFetchで確認し、「※託児、保育、家事のサービスではありません」との明記を確認して本事業とは別物であることを検証した。また「養育支援訪問事業」は要保護児童対策地域協議会が支援要否を判断するハイリスク家庭限定の別制度と判明したため対象から除外した。ファミリーサポートセンターとの直接比較記載は見つからなかったが、本事業は市委託の訪問支援事業者がヘルパーを派遣する方式であり会員間相互援助のファサポとは異なる制度設計であることをuncertainFieldsに記載した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='osaka' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sakai.lg.jp/kosodate/hughug/ninshin_shusan/umaretara/ikujihelper10.html', '「堺市 産前産後ヘルパー」「堺市 育児支援訪問事業」「堺市 産前産後家庭訪問支援事業」「堺市 養育支援訪問事業」で検索。堺市には類似名称の事業が複数あったため、候補を全てWebFetchで実際に読んで峻別した。(1) ikujihelper10.html＝堺市育児支援ヘルパー派遣：対象が妊娠届出日〜出産後1年以内で今回の定義に完全一致、実施要綱とも内容一致を確認。(2) kajiikuji.html＝堺市子育て世帯家事・育児訪問支援事業：名称が似ているが対象は「18歳までの子どもが家事・家族の世話を過度に担っている家庭」＝ヤングケアラー支援であり産前産後とは無関係と判明し除外。(3) sangokea-syukuhaku.html＝産後ケア事業：助産師による母子の心身ケアで「家事援助はできません」と明記されており別事業と確認、混同なし。(4) ファミリーサポートセンターは取得不可だったが会員間マッチング型と判断し対象外。以上により(1)のみを対象制度として採用。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='sakai' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.saitama.lg.jp/003/001/011/p091869.html', '「さいたま市 産前産後ヘルパー」「さいたま市 育児支援訪問事業」等で検索し、さいたま市公式サイト（city.saitama.lg.jp）内の『子育てヘルパー派遣事業』ページ（/003/001/011/p091869.html）と、内容が一致する別URL（/kosodate/shiritai/category6/p103791.html）の2ページをWebFetchで実取得して照合した。両ページとも対象・利用日数・料金・申込方法・問い合わせ先が一致しており信頼性が高いと判断した。さらに一覧ページ（/003/001/011/index.html）を確認し、『産後ケア事業』（訪問型・デイサービス型・宿泊型で産後の母子ケア）と『さいたまファミリー・サポート・センター』（会員相互援助）が本事業とは別項目として並列掲載されていることを確認し、混同がないことを検証済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.hamamatsu-pippi.net/contents/7913.html', '「浜松市 産前産後ヘルパー 派遣事業」で検索し、浜松市の公式子育て情報サイト「ぴっぴ」（認定NPO法人はままつ子育てネットワークぴっぴ運営）内の「はますくヘルパー利用事業」ページをWebFetchで取得し確認した。浜松市公式ドメイン内で同事業を検索したところ、広報はままつのコラム記事タイトルに「はますくヘルパー利用事業（産前・産後ヘルパー）」と明記されているのを確認し、これが指示対象の制度であることを裏付けた。ただし浜松市公式ドメイン直下に制度の恒久的な詳細案内ページは404で存在せず、詳細情報は準公式の『ぴっぴ』サイトに集約されている構成だった。産後ケア事業とは異なる家事・育児ヘルパー派遣であることを確認済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='hamamatsu' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.shizuoka.lg.jp/s2873/s001935.html', '「静岡市 産前産後ヘルパー 派遣事業」で検索し、静岡市公式サイト内の「子育て支援ヘルパー派遣事業」ページを発見。WebFetchで2回取得し、事業名・対象区分（妊婦乳児世帯／多子世帯）・利用時間上限・料金・申請方法・問い合わせ先を確認した。ページ本文の記述から、助産師による産後ケア事業とは異なる家事支援ヘルパー派遣事業であることを確認済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='shizuoka' and t.slug='prenatal-postpartum-helper' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
